-- ============================================================================
-- Quiz Seed: Epistle to Titus (Chapters 1–3)
-- 3 difficulties × 3 chapters = 48 total questions
--   kids:   3 per chapter  =  9
--   teens:  5 per chapter  = 15
--   adults: 8 per chapter  = 24
-- ============================================================================

-- ═══ Titus Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Titus', 1, 'kids', 1, 'Who wrote this letter to Titus?', 'Paul', 'Peter', 'John', 'James', 'a', 'Titus 1:1 — "Paul, a servant of God, and an apostle of Jesus Christ."'),
('Titus', 1, 'kids', 2, 'Where did Paul leave Titus to do church work?', 'Crete', 'Rome', 'Jerusalem', 'Athens', 'a', 'Titus 1:5 — "For this cause left I thee in Crete."'),
('Titus', 1, 'kids', 3, 'What kind of leaders should churches have according to Paul?', 'Blameless and faithful men', 'The richest men', 'The oldest men only', 'Anyone who volunteers', 'a', 'Titus 1:6 — "If any be blameless, the husband of one wife, having faithful children."'),
-- Teens
('Titus', 1, 'teens', 1, 'Why did Paul leave Titus in Crete?', 'To set in order the things that are wanting and ordain elders in every city', 'To build a temple', 'To collect money for Jerusalem', 'To preach to the Roman governor', 'a', 'Titus 1:5 — "For this cause left I thee in Crete, that thou shouldest set in order the things that are wanting, and ordain elders in every city."'),
('Titus', 1, 'teens', 2, 'What must a bishop (overseer) NOT be?', 'Self-willed, soon angry, given to wine, a striker, or greedy of filthy lucre', 'Young and inexperienced', 'Married with children', 'A former Gentile', 'a', 'Titus 1:7 — "not selfwilled, not soon angry, not given to wine, no striker, not given to filthy lucre."'),
('Titus', 1, 'teens', 3, 'What did Paul say about one of Crete''s own prophets?', 'He said Cretians are always liars, evil beasts, and slow bellies — and Paul said this witness is true', 'He praised the Cretians for their wisdom', 'He said Crete would become the center of Christianity', 'He prophesied Crete would be destroyed', 'a', 'Titus 1:12-13 — "One of themselves, even a prophet of their own, said, The Cretians are alway liars, evil beasts, slow bellies. This witness is true."'),
('Titus', 1, 'teens', 4, 'What does Paul say about the circumcision party troublemakers?', 'They subvert whole houses, teaching things they ought not for filthy lucre''s sake — their mouths must be stopped', 'They are sincere but misguided', 'They should be given leadership roles', 'They are the best teachers available', 'a', 'Titus 1:10-11 — "there are many unruly and vain talkers and deceivers, specially they of the circumcision: Whose mouths must be stopped, who subvert whole houses."'),
('Titus', 1, 'teens', 5, 'What does Paul say about the pure and the defiled?', 'Unto the pure all things are pure, but unto them that are defiled and unbelieving is nothing pure', 'The pure must avoid all contact with the defiled', 'The defiled can become pure through rituals', 'Purity is only about outward cleanliness', 'a', 'Titus 1:15 — "Unto the pure all things are pure: but unto them that are defiled and unbelieving is nothing pure."'),
-- Adults
('Titus', 1, 'adults', 1, 'What does Paul say God cannot do in his opening statement?', 'God cannot lie — He promised eternal life before the world began', 'God cannot be seen by human eyes', 'God cannot change His mind', 'God cannot forgive without sacrifice', 'a', 'Titus 1:2 — "In hope of eternal life, which God, that cannot lie, promised before the world began."'),
('Titus', 1, 'adults', 2, 'What positive qualities must a bishop have according to verse 8?', 'A lover of hospitality, a lover of good men, sober, just, holy, temperate', 'Wealthy, educated, well-traveled, politically connected', 'Able to perform miracles, speak in tongues, prophesy', 'From a priestly family, trained in the law, circumcised', 'a', 'Titus 1:8 — "a lover of hospitality, a lover of good men, sober, just, holy, temperate."'),
('Titus', 1, 'adults', 3, 'What must a bishop be able to do with sound doctrine?', 'Hold fast the faithful word, be able to exhort and convince the gainsayers by sound doctrine', 'Write extensive theological treatises', 'Debate in the public square for entertainment', 'Translate the Scriptures into multiple languages', 'a', 'Titus 1:9 — "Holding fast the faithful word as he hath been taught, that he may be able by sound doctrine both to exhort and to convince the gainsayers."'),
('Titus', 1, 'adults', 4, 'What does Paul say about the mind and conscience of the defiled?', 'Even their mind and conscience is defiled', 'Their mind is sharp but their conscience is weak', 'Their mind is pure but their actions are defiled', 'Only their conscience is affected, not their mind', 'a', 'Titus 1:15 — "unto them that are defiled and unbelieving is nothing pure; but even their mind and conscience is defiled."'),
('Titus', 1, 'adults', 5, 'How does Paul describe the false professors in verse 16?', 'They profess that they know God, but in works they deny Him, being abominable, disobedient, and unto every good work reprobate', 'They deny God openly and worship idols', 'They are sincere seekers who need more instruction', 'They are new converts who will grow in time', 'a', 'Titus 1:16 — "They profess that they know God; but in works they deny him, being abominable, and disobedient, and unto every good work reprobate."'),
('Titus', 1, 'adults', 6, 'What is Paul''s relationship to Titus as stated in the greeting?', '"Mine own son after the common faith" — indicating Paul led Titus to Christ', 'His biological nephew', 'A hired scribe', 'A fellow prisoner', 'a', 'Titus 1:4 — "To Titus, mine own son after the common faith."'),
('Titus', 1, 'adults', 7, 'When does Paul say eternal life was promised?', 'Before the world began — emphasizing God''s eternal, pre-temporal purpose', 'At the time of Abraham', 'At Mount Sinai', 'At the coming of Christ', 'a', 'Titus 1:2 — "In hope of eternal life, which God, that cannot lie, promised before the world began."'),
('Titus', 1, 'adults', 8, 'What does Paul say about paying attention to Jewish fables?', 'Not giving heed to Jewish fables and commandments of men that turn from the truth', 'Jewish fables contain hidden wisdom', 'Only elders should study Jewish fables', 'Jewish fables are profitable for teaching children', 'a', 'Titus 1:14 — "Not giving heed to Jewish fables, and commandments of men, that turn from the truth."');

-- ═══ Titus Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Titus', 2, 'kids', 1, 'What does Paul say has appeared to all men?', 'The grace of God that bringeth salvation', 'A bright star', 'A new king', 'A great earthquake', 'a', 'Titus 2:11 — "the grace of God that bringeth salvation hath appeared to all men."'),
('Titus', 2, 'kids', 2, 'What does Paul tell young men to be?', 'Sober minded (self-controlled)', 'Rich and powerful', 'Famous and popular', 'Silent and unseen', 'a', 'Titus 2:6 — "Young men likewise exhort to be sober minded."'),
('Titus', 2, 'kids', 3, 'Who gave Himself for us to redeem us?', 'Jesus Christ', 'Moses', 'Abraham', 'David', 'a', 'Titus 2:14 — "Who gave himself for us, that he might redeem us from all iniquity."'),
-- Teens
('Titus', 2, 'teens', 1, 'What should Titus speak according to sound doctrine?', 'Things that become (are consistent with) sound doctrine', 'Only pleasant and agreeable things', 'Complex theological arguments', 'Prophecies about the future', 'a', 'Titus 2:1 — "speak thou the things which become sound doctrine."'),
('Titus', 2, 'teens', 2, 'What does grace teach us to deny?', 'Ungodliness and worldly lusts, and to live soberly, righteously, and godly in this present world', 'All pleasure and enjoyment', 'All forms of work and employment', 'All contact with unbelievers', 'a', 'Titus 2:12 — "Teaching us that, denying ungodliness and worldly lusts, we should live soberly, righteously, and godly, in this present world."'),
('Titus', 2, 'teens', 3, 'What blessed hope are believers looking for?', 'The glorious appearing of the great God and our Saviour Jesus Christ', 'A new earthly kingdom', 'The rebuilding of the temple', 'The defeat of Rome', 'a', 'Titus 2:13 — "Looking for that blessed hope, and the glorious appearing of the great God and our Saviour Jesus Christ."'),
('Titus', 2, 'teens', 4, 'What should older women teach the younger women?', 'To be sober, to love their husbands and children, to be discreet, chaste, keepers at home, good, obedient to their husbands', 'To pursue careers outside the home', 'To seek positions of public authority', 'To focus only on personal spiritual growth', 'a', 'Titus 2:4-5 — "teach the young women to be sober, to love their husbands, to love their children, To be discreet, chaste, keepers at home, good, obedient to their own husbands."'),
('Titus', 2, 'teens', 5, 'What should Titus show himself as in all things?', 'A pattern of good works, with uncorruptness, gravity, and sincerity in doctrine', 'A powerful miracle worker', 'A wealthy patron', 'A stern judge', 'a', 'Titus 2:7 — "In all things shewing thyself a pattern of good works: in doctrine shewing uncorruptness, gravity, sincerity."'),
-- Adults
('Titus', 2, 'adults', 1, 'What qualities does Paul require of aged men?', 'Sober, grave, temperate, sound in faith, in charity, in patience', 'Wealthy, influential, and well-connected', 'Able to recite the law from memory', 'Retired from all church responsibilities', 'a', 'Titus 2:2 — "That the aged men be sober, grave, temperate, sound in faith, in charity, in patience."'),
('Titus', 2, 'adults', 2, 'What reason does Paul give for good behavior — "that the word of God be not..."?', 'Blasphemed', 'Forgotten', 'Misunderstood', 'Complicated', 'a', 'Titus 2:5 — "that the word of God be not blasphemed."'),
('Titus', 2, 'adults', 3, 'What does Paul say sound speech that cannot be condemned achieves?', 'That he that is of the contrary part may be ashamed, having no evil thing to say of us', 'That we gain political influence', 'That we become famous orators', 'That we silence all opposition permanently', 'a', 'Titus 2:8 — "Sound speech, that cannot be condemned; that he that is of the contrary part may be ashamed, having no evil thing to say of you."'),
('Titus', 2, 'adults', 4, 'What does Paul tell servants to do to adorn the doctrine?', 'Be obedient, well pleasing, not answering again, not purloining, showing good fidelity — adorning the doctrine of God our Saviour in all things', 'Demand their freedom in the name of Christ', 'Only serve Christian masters', 'Focus on spiritual matters rather than work', 'a', 'Titus 2:9-10 — "Exhort servants to be obedient unto their own masters… not purloining, but shewing all good fidelity; that they may adorn the doctrine of God our Saviour in all things."'),
('Titus', 2, 'adults', 5, 'What Christological title does Titus 2:13 use that affirms Christ''s deity?', '"The great God and our Saviour Jesus Christ" — the Granville Sharp rule in Greek indicates one person, affirming Christ as God', '"The Son of God" only', '"A teacher sent from God"', '"The prophet like Moses"', 'a', 'Titus 2:13 — "the glorious appearing of the great God and our Saviour Jesus Christ."'),
('Titus', 2, 'adults', 6, 'What does Paul say Christ redeemed us from and purified us for?', 'Redeemed from all iniquity and purified unto Himself a peculiar people, zealous of good works', 'Redeemed from Roman slavery and purified for heaven only', 'Redeemed from sickness and purified from disease', 'Redeemed from poverty and purified for prosperity', 'a', 'Titus 2:14 — "Who gave himself for us, that he might redeem us from all iniquity, and purify unto himself a peculiar people, zealous of good works."'),
('Titus', 2, 'adults', 7, 'How does Paul tell Titus to teach these things?', 'Speak, exhort, and rebuke with all authority; let no man despise thee', 'Suggest gently without pressing the point', 'Only teach when asked', 'Write letters rather than speak in person', 'a', 'Titus 2:15 — "These things speak, and exhort, and rebuke with all authority. Let no man despise thee."'),
('Titus', 2, 'adults', 8, 'What three time perspectives does Titus 2:12-13 address for Christian living?', 'Past (denying ungodliness), present (living soberly, righteously, godly), and future (looking for the blessed hope)', 'Past sins, present duties, future rewards only', 'Law, grace, and glory ages', 'Creation, fall, and redemption narratives', 'a', 'Titus 2:12-13 covers the past renunciation of ungodliness, present godly living, and future hope of Christ''s appearing.');

-- ═══ Titus Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Titus', 3, 'kids', 1, 'What does Paul say we should be ready to do?', 'Every good work', 'Fight our enemies', 'Hide from strangers', 'Build big houses', 'a', 'Titus 3:1 — "Put them in mind to be subject to principalities and powers… to be ready to every good work."'),
('Titus', 3, 'kids', 2, 'How did God save us?', 'By His mercy, not by our works', 'Because we were good enough', 'Because we followed all the rules', 'Because we earned it', 'a', 'Titus 3:5 — "Not by works of righteousness which we have done, but according to his mercy he saved us."'),
('Titus', 3, 'kids', 3, 'What does Paul say to avoid?', 'Foolish questions and arguments', 'All new people', 'Books and reading', 'Fun and games', 'a', 'Titus 3:9 — "avoid foolish questions, and genealogies, and contentions."'),
-- Teens
('Titus', 3, 'teens', 1, 'What does Paul say about speaking evil of others?', 'Speak evil of no man, be no brawlers, but gentle, shewing all meekness unto all men', 'Speak evil only of unbelievers', 'Speak evil only when it is true', 'Speak evil to protect the church', 'a', 'Titus 3:2 — "To speak evil of no man, to be no brawlers, but gentle, shewing all meekness unto all men."'),
('Titus', 3, 'teens', 2, 'What does Paul say we ourselves were before salvation?', 'Foolish, disobedient, deceived, serving divers lusts and pleasures, living in malice and envy', 'Always good and righteous', 'Slightly sinful but mostly good', 'Ignorant but innocent', 'a', 'Titus 3:3 — "we ourselves also were sometimes foolish, disobedient, deceived, serving divers lusts and pleasures, living in malice and envy, hateful, and hating one another."'),
('Titus', 3, 'teens', 3, 'What two things does Paul say God saved us by?', 'The washing of regeneration and renewing of the Holy Ghost', 'Baptism in water and keeping the law', 'Circumcision and sacrifice', 'Fasting and prayer', 'a', 'Titus 3:5 — "by the washing of regeneration, and renewing of the Holy Ghost."'),
('Titus', 3, 'teens', 4, 'What should a heretical person be given before being rejected?', 'A first and second admonition (warning)', 'Three chances over three years', 'No warning at all', 'A chance to debate publicly', 'a', 'Titus 3:10 — "A man that is an heretick after the first and second admonition reject."'),
('Titus', 3, 'teens', 5, 'Who does Paul plan to send to Titus in Crete?', 'Artemas or Tychicus', 'Timothy and Silas', 'Peter and John', 'Luke and Mark', 'a', 'Titus 3:12 — "When I shall send Artemas unto thee, or Tychicus."'),
-- Adults
('Titus', 3, 'adults', 1, 'What does Paul call the moment of conversion using Christological language?', '"The kindness and love of God our Saviour toward man appeared" — using "epiphany" language parallel to Titus 2:11', '"The law of God was finally understood"', '"The prophecies of the Old Testament were fulfilled"', '"The temple was spiritually rebuilt in our hearts"', 'a', 'Titus 3:4 — "after that the kindness and love of God our Saviour toward man appeared."'),
('Titus', 3, 'adults', 2, 'What is the relationship between works and salvation in Titus 3:5?', 'Salvation is not by works of righteousness we have done but according to God''s mercy — works are explicitly excluded as the basis', 'Works contribute partially to salvation', 'Works are the evidence that completes salvation', 'Works prepare us to receive salvation', 'a', 'Titus 3:5 — "Not by works of righteousness which we have done, but according to his mercy he saved us."'),
('Titus', 3, 'adults', 3, 'How does Paul describe the Holy Spirit''s role in salvation?', 'God shed the Holy Ghost abundantly through Jesus Christ our Saviour', 'The Spirit only convicts of sin', 'The Spirit operates independently of Christ', 'The Spirit is given only to apostles', 'a', 'Titus 3:5-6 — "the renewing of the Holy Ghost; Which he shed on us abundantly through Jesus Christ our Saviour."'),
('Titus', 3, 'adults', 4, 'What is the purpose of justification according to verse 7?', 'That being justified by His grace we should be made heirs according to the hope of eternal life', 'That we might boast in our own righteousness', 'That we might judge others', 'That we might earn rewards in heaven', 'a', 'Titus 3:7 — "That being justified by his grace, we should be made heirs according to the hope of eternal life."'),
('Titus', 3, 'adults', 5, 'What does Paul call the statement about salvation by mercy a "faithful saying" for?', 'So that those who have believed in God might be careful to maintain good works — the "faithful saying" connects right doctrine to right practice', 'So that it might be memorized', 'So that it can be used in debates', 'So that unbelievers can understand it', 'a', 'Titus 3:8 — "This is a faithful saying, and these things I will that thou affirm constantly, that they which have believed in God might be careful to maintain good works."'),
('Titus', 3, 'adults', 6, 'What four things does Paul say to avoid?', 'Foolish questions, genealogies, contentions, and strivings about the law — they are unprofitable and vain', 'Meat, wine, festivals, and markets', 'Greeks, Romans, Egyptians, and Persians', 'Morning prayer, evening prayer, fasting, and almsgiving', 'a', 'Titus 3:9 — "But avoid foolish questions, and genealogies, and contentions, and strivings about the law; for they are unprofitable and vain."'),
('Titus', 3, 'adults', 7, 'What does Paul say about a heretic after two admonitions?', 'He is subverted and sinneth, being condemned of himself', 'He may still be converted with patience', 'He should be given unlimited chances', 'He deserves physical punishment', 'a', 'Titus 3:10-11 — "A man that is an heretick after the first and second admonition reject; Knowing that he that is such is subverted, and sinneth, being condemned of himself."'),
('Titus', 3, 'adults', 8, 'What practical instruction does Paul give about Zenas and Apollos?', 'Bring them on their journey diligently, that nothing be wanting unto them', 'Send them to Jerusalem for further training', 'Warn them about false teachers in Crete', 'Ask them to stay and help Titus', 'a', 'Titus 3:13 — "Bring Zenas the lawyer and Apollos on their journey diligently, that nothing be wanting unto them."');
